12	export function runScenario(scenario: any): { results: unknown[] } {
13	  const results: unknown[] = [];
14	  let quoteCount = 0;
15	  const remainingCaps = new Map<number, number>();
16	  for (const step of scenario.steps) {
17	    if (step.op === "quote") {
18	      for (const item of step.items) {
19	        if (!KNOWN_ITEM_TYPES.has(item.type)) {
20	          throw new Error(`Unknown item type: ${item.type}`);
21	        }
22	      }
23	      const premium = quote({
24	        customer: {
25	          yearsWithMHPCO: scenario.customer.yearsWithMHPCO,
26	          previousContracts: quoteCount,
27	        },
28	        items: step.items,
29	      });
30	      results.push({ premium });
31	      quoteCount++;
32	    } else if (step.op === "claim") {
33	      const policyStep = scenario.steps[step.policy];
34	      const { payout, remainingCap } = claim({
35	        items: policyStep.items,
36	        incident: step.incident,
37	        remainingCap: remainingCaps.get(step.policy),
38	      });
39	      remainingCaps.set(step.policy, remainingCap);
40	      results.push({ payout, remainingCap });
41	    }
42	  }
43	  return { results };
44	}
